# @cctt_verify {"v":2,"sym":"sympy.simplify.tests.test_combsimp.test_combsimp","kind":"function","src_hash":"099259549d8556e2","in":{"base":"Any"},"out":{"base":"Any","pred":"combsimp(factorial(n)) == factorial(n) and combsimp(binomial(n, k)) == binomial(n, k) and combsimp(factorial(n) / factorial(n - 3)) == n * (-1 + n) * (-2 + n) and combsimp(binomial(n + 1, k + 1) / binomial(n, k)) == (1 + n) / (1 + k) and combsimp(gamma(n + 3)) == factorial(n + 2) and combsimp(factorial(x)) == gamma(x + 1) and combsimp((n + 1) * factorial(n)) == factorial(n + 1) and combsimp(factorial(n) / n) == factorial(n - 1) and combsimp(binomial(n, n - k)) == binomial(n, k) and combsimp(factorial(n) / (factorial(k) * factorial(n - k))) == binomial(n, k) and combsimp(factorial(k) * factorial(n - k) / factorial(n)) == 1 / binomial(n, k) and combsimp(factorial(2 * n) / factorial(n) ** 2) == binomial(2 * n, n) and combsimp(factorial(n * (1 + n) - n ** 2 - n)) == 1"},"spec":{"lhs":"test_combsimp()","rhs":"test_combsimp produces the expected output","over":{"base":"Any"},"name":"test_combsimp_correct"},"guarantee":"test_combsimp produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.simplify.tests.test_combsimp.test_combsimp_correct","statement":"Path(test_combsimp(x), test_combsimp produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"11625b00d75e372a"}
def test_combsimp():
    k, m, n = symbols('k m n', integer = True)

    assert combsimp(factorial(n)) == factorial(n)
    assert combsimp(binomial(n, k)) == binomial(n, k)

    assert combsimp(factorial(n)/factorial(n - 3)) == n*(-1 + n)*(-2 + n)
    assert combsimp(binomial(n + 1, k + 1)/binomial(n, k)) == (1 + n)/(1 + k)

    assert combsimp(binomial(3*n + 4, n + 1)/binomial(3*n + 1, n)) == \
        Rational(3, 2)*((3*n + 2)*(3*n + 4)/((n + 1)*(2*n + 3)))

    assert combsimp(factorial(n)**2/factorial(n - 3)) == \
        factorial(n)*n*(-1 + n)*(-2 + n)
    assert combsimp(factorial(n)*binomial(n + 1, k + 1)/binomial(n, k)) == \
        factorial(n + 1)/(1 + k)

    assert combsimp(gamma(n + 3)) == factorial(n + 2)

    assert combsimp(factorial(x)) == gamma(x + 1)

    # issue 9699
    assert combsimp((n + 1)*factorial(n)) == factorial(n + 1)
    assert combsimp(factorial(n)/n) == factorial(n-1)

    # issue 6658
    assert combsimp(binomial(n, n - k)) == binomial(n, k)

    # issue 6341, 7135
    assert combsimp(factorial(n)/(factorial(k)*factorial(n - k))) == \
        binomial(n, k)
    assert combsimp(factorial(k)*factorial(n - k)/factorial(n)) == \
        1/binomial(n, k)
    assert combsimp(factorial(2*n)/factorial(n)**2) == binomial(2*n, n)
    assert combsimp(factorial(2*n)*factorial(k)*factorial(n - k)/
        factorial(n)**3) == binomial(2*n, n)/binomial(n, k)

    assert combsimp(factorial(n*(1 + n) - n**2 - n)) == 1

    assert combsimp(6*FallingFactorial(-4, n)/factorial(n)) == \
        (-1)**n*(n + 1)*(n + 2)*(n + 3)
    assert combsimp(6*FallingFactorial(-4, n - 1)/factorial(n - 1)) == \
        (-1)**(n - 1)*n*(n + 1)*(n + 2)
    assert combsimp(6*FallingFactorial(-4, n - 3)/factorial(n - 3)) == \
        (-1)**(n - 3)*n*(n - 1)*(n - 2)
    assert combsimp(6*FallingFactorial(-4, -n - 1)/factorial(-n - 1)) == \
        -(-1)**(-n - 1)*n*(n - 1)*(n - 2)

    assert combsimp(6*RisingFactorial(4, n)/factorial(n)) == \
        (n + 1)*(n + 2)*(n + 3)
    assert combsimp(6*RisingFactorial(4, n - 1)/factorial(n - 1)) == \
        n*(n + 1)*(n + 2)
    assert combsimp(6*RisingFactorial(4, n - 3)/factorial(n - 3)) == \
        n*(n - 1)*(n - 2)
    assert combsimp(6*RisingFactorial(4, -n - 1)/factorial(-n - 1)) == \
        -n*(n - 1)*(n - 2)


